B.agL=new A.b3("Con \u0111\u01b0\u1eddng nh\u1eadp m\xf4n n\u0103m x\u01b0a gi\u1edd \u0111\u1ea7y tro t\xe0n. T\u1eeb \u0111\xe2y, ta kh\xf4ng c\xf2n \u0111\u01b0\u1eddng lui.","Ta b\u01b0\u1edbc ti\u1ebfp kh\xf4ng ph\u1ea3i \u0111\u1ec3 n\u1ed5i danh; cha m\u1eb9 ta \u0111\xe3 y\xean ngh\u1ec9 v\xec tu\u1ed5i gi\xe0, v\xe0 l\u1eddi d\u1eb7n cu\u1ed1i c\u1ee7a h\u1ecd l\xe0 \u0111\u1eebng b\u1ecf m\u1eb7c ng\u01b0\u1eddi y\u1ebfu gi\u1eefa lo\u1ea1n \u0111\u1eddi.",null)
B.ahg=new A.b3("B\u01b0\u1edbc qua \u0111\xe2y l\xe0 m\xe1u, l\xf9i l\u1ea1i l\xe0 h\u1ed1i h\u1eadn.","Ta s\u1ed1ng s\xf3t, nh\u01b0ng kh\xf4ng th\u1ec3 ti\u1ebfp t\u1ee5c s\u1ed1ng v\xf4 ngh\u0129a.",null)
B.agG=new A.b3("Ng\u01b0\u01a1i \u0111\xe1nh v\xec danh, ta \u0111\xe1nh v\xec \u0111\u01b0\u1eddng v\u1ec1 nh\xe0.","M\u1ed7i k\u1ebb g\u1ee5c xu\u1ed1ng \u0111\u1ec1u t\u1eebng l\xe0 ai \u0111\xf3 c\u1ee7a m\u1ed9t gia \u0111\xecnh.",null)
B.agY=new A.b3("Tro t\xe0n b\xe1m v\xe0o \xe1o, kh\xf4ng g\u1ed9t \u0111\u01b0\u1ee3c b\u1eb1ng n\u01b0\u1edbc.","Ta kh\xf4ng c\xf2n t\xecm th\u1eafng thua, ta t\xecm l\u1ed1i \u0111\u1ec3 ng\u01b0\u1eddi kh\xe1c kh\u1ecfi m\u1ea5t nh\xe0.",null)
B.agN=new A.b3("N\u1ebfu ta b\u1ecf ch\u1ea1y n\u1eefa, s\u1ebd l\u1ea1i c\xf3 ng\u01b0\u1eddi ch\u1ebft thay ta.","N\u1ed7i s\u1ee3 v\u1eabn c\xf2n, nh\u01b0ng ch\xe2n ta kh\xf4ng l\xf9i n\u1eefa.",null)
B.agH=new A.b3("Ng\u01b0\u01a1i th\u1eafng v\xe0i tr\u1eadn nh\u1ecf r\u1ed3i t\u01b0\u1edfng \u0111\xe3 hi\u1ec3u lo\u1ea1n th\u1ebf? H\xe3y tr\u1ea3 l\u1eddi b\u1eb1ng m\xe1u c\u1ee7a ch\xednh ng\u01b0\u01a1i.","Ta r\u1eddi khu r\u1eebng n\xe0y kh\xf4ng c\xf2n l\xe0 k\u1ebb tr\u1ed1n n\u1ea1n. T\u1eeb nay, ta \u0111i \u0111\u1ec3 ch\u1ea5m d\u1ee9t v\xf2ng l\u1eb7p hi sinh.","N\u1ebfu g\u1ee5c t\u1ea1i \u0111\xe2y, t\xf4ng m\xf4n v\xe0 gia \u0111\xecnh ta s\u1ebd m\xe3i ch\u1ec9 l\xe0 m\u1ed9t d\xf2ng ch\u1eef trong bia m\u1ed9.")
