B.a7H={starter_forest:0,blazing_ruins:1,enkavia:2,reverse_world:3,sealed_void:4}
B.agD=new A.ql("Ch\u01b0\u01a1ng 1 - R\u1eebng T\xe2n Th\u1ee7","R\u1eebng c\u0169 v\u1eabn xanh, ch\u1ec9 l\xf2ng ng\u01b0\u1eddi \u0111\xe3 \u0111\u1ed5i m\xe0u. Ta tr\u1edf l\u1ea1i n\u01a1i nh\u1eadp m\xf4n n\u0103m x\u01b0a sau l\u1ec5 tang song th\xe2n \u0111\xe3 m\xe3n th\u1ecd, kh\xf4ng c\xf2n l\xe0 \u0111\u1ec7 t\u1eed c\u0169 m\xe0 l\xe0 k\u1ebb s\u1ed1ng s\xf3t \u0111i gi\u1eef l\u1eddi h\u1ee9a mu\u1ed9n v\u1edbi gia \u0111\xecnh.")
B.agE=new A.ql("Ch\u01b0\u01a1ng 2 - T\xe0n T\xedch Vi\xeam","T\xe0n t\xedch n\xe0y ch\xe1y kh\xf4ng ch\u1ec9 b\u1edfi l\u1eeda, m\xe0 b\u1edfi cu\u1ed9c tranh \u0111o\u1ea1t Linh M\u1ea1ch Vi\xeam T\xe2m gi\u1eefa th\u01b0\u01a1ng h\u1ed9i v\xe0 n\u1ed9i ph\u1ea3n trong c\xe1c t\xf4ng m\xf4n. Ta \u0111i s\xe2u v\xe0o tro t\xe0n \u0111\u1ec3 l\u1ea5y ch\u1ee9ng c\u1ee9 cu\u1ed1i, v\u1ea1ch r\xf5 ai \u0111\xe3 ch\xe2m ng\xf2i chi\u1ebfn cu\u1ed9c h\u1ee7y di\u1ec7t t\xf4ng m\xf4n c\u1ee7a ta.")
B.agB=new A.ql("Ch\u01b0\u01a1ng 3 - \u0110\xe1y Bi\u1ec3n Enkavia","Bi\u1ec3n s\xe2u Enkavia c\u1ea5t gi\u1eef phong \u1ea5n k\xfd \u1ee9c v\u1ec1 to\xe0n b\u1ed9 v\u1ee5 ph\u1ea3n b\u1ed9i. N\u1ebfu m\u1edf \u0111\u01b0\u1ee3c phong \u1ea5n n\xe0y v\xe0 c\xf4ng b\u1ed1 tr\u01b0\u1edbc thi\xean h\u1ea1, ta c\xf3 th\u1ec3 kh\xe9p l\u1ea1i v\xf2ng l\u1eb7p ch\xe9m gi\u1ebft, m\u1edf ra m\u1ed9t tr\u1eadt t\u1ef1 m\u1edbi n\u01a1i k\u1ebb y\u1ebfu kh\xf4ng c\xf2n b\u1ecb \u0111em l\xe0m v\u1eadt hi sinh.")
B.agF=new A.ql("Ch\u01b0\u01a1ng 4 - Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c","Sau khi tho\xe1t kh\u1ecfi Enkavia, thuy\u1ec1n c\u1ee7a ta v\u1eeba r\u1eddi m\u1eb7t bi\u1ec3n ch\u01b0a bao xa th\xec to\xe0n b\u1ed9 h\u1ea3i l\u01b0u b\u1ed7ng xo\u1eafn l\u1ea1i th\xe0nh m\u1ed9t l\u1ed7 h\u1ed5ng kh\xf4ng gian. Khi m\u1edf m\u1eaft, tr\u01b0\u1edbc m\u1eb7t ta l\xe0 m\u1ed9t th\u1ebf gi\u1edbi \u0111\u1ea3o ng\u01b0\u1ee3c: bi\u1ec3n treo tr\xean tr\u1eddi, th\xe0nh qu\xe1ch l\u1eadt \xfap, m\xf9a m\xe0ng ch\u1ea3y ng\u01b0\u1ee3c v\u1ec1 tro b\u1ee5i, c\xf2n nh\u1eefng con ng\u01b0\u1eddi m\u1eafc k\u1eb9t \u1edf \u0111\xe2y th\xec v\u1eeba s\u1ed1ng nh\u01b0 th\u1eadt, v\u1eeba nh\u01b0 \u0111ang b\u1ecb k\xfd \u1ee9c c\u1ee7a ch\xednh m\xecnh n\xedu l\u1ea1i. Nh\u01b0ng \u1edf Th\u1ebf Gi\u1edbi \u0110\u1ea3o Ng\u01b0\u1ee3c, m\u1ed7i node ch\u1ec9 cho ng\u01b0\u1eddi ch\u01a1i d\xf9ng \u0111\xfang 1 trong 5 k\u1ef9 n\u0103ng, v\xe0 kho\xe1 n\xe0y l\xe0 c\u1ed1 \u0111\u1ecbnh theo node. Mu\u1ed1n r\u1eddi kh\u1ecfi n\u01a1i n\xe0y, ta ch\u1ec9 c\xf2n c\xe1ch \u0111i t\u1edbi t\u1eadn c\xf9ng, l\u1ea7n theo t\u1eebng phi\u1ebfn \u0111\xe1 c\u1ed5 v\xe0 nghe h\u1ebft nh\u1eefng c\xe2u chuy\u1ec7n ch\u01b0a ai d\xe1m kh\xe9p l\u1ea1i.")
B.agC=new A.ql("Ch\u01b0\u01a1ng 5 - H\u01b0 V\u1ef1c Phong \u1ea4n (S\u1eafp M\u1edf)","C\xe1nh c\u1ed5ng H\u01b0 V\u1ef1c v\u1eabn b\u1ecb ni\xeam phong. Khi th\u1eddi \u0111i\u1ec3m \u0111\u1ebfn, h\xe0nh tr\xecnh k\u1ebf ti\u1ebfp s\u1ebd m\u1edf ra c\xf9ng ch\xe2n t\u01b0\u1edbng sau c\xf9ng.")
