B.ahc=new A.b3("\u1ede b\u1ebfn thuy\u1ec1n n\xe0y c\xf3 m\u1ed9t ng\u01b0\u1eddi \u0111\xe0n b\xe0 v\u1eabn ng\u1ed3i v\xe1 l\u01b0\u1edbi gi\u1eefa n\u01b0\u1edbc bi\u1ec3n treo ng\u01b0\u1ee3c. B\xe0 v\xe1 m\xe3i m\u1ed9t t\u1ea5m l\u01b0\u1edbi kh\xf4ng bao gi\u1edd d\xf9ng \u0111\u01b0\u1ee3c, nh\u01b0 \u0111ang c\u1ed1 n\xedu m\u1ed9t ai \u0111\xf3 ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c c\u1ee9u v\u1ec1.",'B\xe0 t\u1eebng l\xe0 m\u1eb9 c\u1ee7a ba \u0111\u1ee9a tr\u1ebb s\u1ed1ng b\u1eb1ng ngh\u1ec1 ch\xe0i l\u01b0\u1edbi. Trong m\u1ed9t \u0111\xeam bi\u1ec3n n\u1ed5i c\u01a1n \u0111\u1ed9ng lo\u1ea1n, b\u1ecdn bu\xf4n ng\u01b0\u1eddi gi\u1ea3 thuy\u1ec1n c\u1ee9u n\u1ea1n \u0111\xe3 b\u1eaft m\u1ea5t c\u1ea3 ba \u0111\u1ee9a, c\xf2n quan tu\u1ea7n h\u1ea3i \u0103n ti\u1ec1n \u0111\u1ec3 n\xf3i r\u1eb1ng ch\xfang ch\u1ec9 "tr\xf4i d\u1ea1t m\u1ea5t t\xedch". Khi b\u1ecb k\xe9o v\xe0o Ngh\u1ecbch H\u1ea3i, b\xe0 \u0111i\xean d\u1ea1i \u0111\u1ebfn m\u1ee9c ng\xe0y n\xe0o c\u0169ng v\xe1 l\u01b0\u1edbi v\u1edbi hi v\u1ecdng m\u1ed9t s\u1edbm n\xe0o \u0111\xf3 th\u1ea3 l\u01b0\u1edbi xu\u1ed1ng s\u1ebd v\u1edbt \u0111\xfang con m\xecnh l\xean. Ta kh\xf4ng th\u1ec3 tr\u1ea3 con cho b\xe0, ch\u1ec9 c\xf3 th\u1ec3 gi\xfap b\xe0 kh\u1eafc \u0111\u1ee7 ba c\xe1i t\xean l\xean m\u1ea1n thuy\u1ec1n \u0111\u1ec3 t\u1eeb nay n\u1ed7i nh\u1edb \u1ea5y th\xf4i b\u1ecb g\u1ecdi l\xe0 hoang t\u01b0\u1edfng.',null)
B.ahB=new A.b3("X\xf3m \u0111\xe8n treo h\xe0ng tr\u0103m ng\u1ecdn h\u1ea3i \u0111\u0103ng nh\u1ecf, nh\u01b0ng ch\u1eb3ng ng\u1ecdn n\xe0o soi \u0111\u01b0\u1eddng cho thuy\u1ec1n s\u1ed1ng. Ch\xfang ch\u1ec9 ch\xe1y khi c\xf3 m\u1ed9t c\xe1i t\xean ng\u01b0\u1eddi ch\u1ebft \u0111\u01b0\u1ee3c th\xec th\u1ea7m trong gi\xf3.","Ng\u01b0\u1eddi gi\u1eef \u0111\xe8n t\u1eebng l\xe0 m\u1ed9t thi\u1ebfu ni\xean s\u1ed1ng s\xf3t duy nh\u1ea5t sau v\u1ee5 ch\xe1y t\xe0u c\u1ee9u tr\u1ee3. C\u1eadu b\u1ecb nh\u1ed1t d\u01b0\u1edbi khoang c\xf9ng d\xe2n ch\u1ea1y n\u1ea1n, nghe ti\u1ebfng m\u1eb9 m\xecnh g\xf5 c\u1eeda su\u1ed1t m\u1ed9t \u0111\xeam r\u1ed3i d\u1ea7n im h\u1eb3n, \u0111\u1ec3 \u0111\u1ed5i l\u1ea1i vi\u1ec7c b\u1ecdn bu\xf4n ng\u01b0\u1eddi tha cho c\u1eadu m\u1ea1ng s\u1ed1ng l\xe0m k\u1ebb qu\xe9t boong. Nhi\u1ec1u n\u0103m sau c\u1eadu \u0111\u1ed1t \u0111\xe8n cho t\u1eebng ng\u01b0\u1eddi \u0111\xe3 ch\u1ebft m\xe0 kh\xf4ng ai nh\u1eadn x\xe1c, v\xec s\u1ee3 n\u1ebfu t\u1eaft h\u1ebft \u0111\xe8n th\xec ti\u1ebfng g\xf5 c\u1eeda \u0111\xeam \u0111\xf3 s\u1ebd quay l\u1ea1i t\xecm m\xecnh. Ta d\u1eadp tr\u1eadn o\xe1n \u1edf \u0111\xe2y kh\xf4ng ph\u1ea3i \u0111\u1ec3 c\u1eadu qu\xean, m\xe0 \u0111\u1ec3 c\u1eadu bi\u1ebft c\xf3 ng\u01b0\u1eddi kh\xe1c cu\u1ed1i c\xf9ng c\u0169ng nghe th\u1ea5y ti\u1ebfng g\u1ecdi c\u1ee7a nh\u1eefng ng\u01b0\u1eddi \u0111\xe3 ch\xecm.",null)
B.ah0=new A.b3('Ngh\u0129a trang san h\xf4 kh\xf4ng ch\xf4n x\xe1c, ch\u1ec9 ch\xf4n nh\u1eefng b\xe0i v\u1ecb tr\u1eafng. M\u1ed7i t\u1ea5m b\xe0i v\u1ecb \u0111\u1ec1u kh\u1eafc m\u1ed9t c\xe2u gi\u1ed1ng nhau: "ch\u01b0a t\xecm th\u1ea5y th\xe2n".',"L\xe3o gi\u1eef ngh\u0129a trang t\u1eebng l\xe0 ng\u01b0\u1eddi \u0111\xe0o m\u1ed3 thu\xea cho v\xf9ng c\u1ea3ng. Sau tr\u1eadn d\u1ecbch bi\u1ec3n, l\xe3o \u0111\u01b0\u1ee3c thu\xea v\u1ee9t x\xe1c d\xe2n ngh\xe8o xu\u1ed1ng v\u1ef1c \u0111\u1ec3 che s\u1ed1 ng\u01b0\u1eddi ch\u1ebft th\u1eadt, \u0111\u1ed5i l\u1ea1i l\xe0 thu\u1ed1c cho \u0111\u1ee9a ch\xe1u n\u1ed9i h\u1ea5p h\u1ed1i. Thu\u1ed1c kh\xf4ng c\u1ee9u \u0111\u01b0\u1ee3c ch\xe1u, c\xf2n \u0111\xf4i tay l\xe3o t\u1eeb \u0111\xf3 ch\u1ec9 quen c\u1ea7m b\xe0i v\u1ecb tr\u1eafng v\xec kh\xf4ng d\xe1m vi\u1ebft t\xean nh\u1eefng ng\u01b0\u1eddi m\xecnh \u0111\xe3 gi\u1ea5u x\xe1c. Ta gi\xfap l\xe3o d\u1ef1ng bia, vi\u1ebft l\u1ea1i t\u1eebng c\xe1i t\xean t\u1eeb s\u1ed5 quan ph\u1ee7 b\u1ecb x\xf3a, \u0111\u1ec3 l\u1ea7n \u0111\u1ea7u ti\xean nh\u1eefng ng\u01b0\u1eddi \u1ea5y c\xf3 m\u1ed9 v\xe0 k\u1ebb ch\xf4n h\u1ecd c\u0169ng c\xf3 quy\u1ec1n \u0111\u01b0\u1ee3c kh\xf3c.",null)
B.ahI=new A.b3("Trong khoang t\xe0u m\u1ee5c n\xe1t v\u1eabn c\xf2n ti\u1ebfng tr\u1ebb con \u0111\u1ebfm s\u1ed1. C\u1ee9 \u0111\u1ebfm t\u1edbi m\u01b0\u1eddi l\xe0 l\u1ea1i l\u1eb7ng \u0111i, nh\u01b0 th\u1ec3 c\xf3 \u0111\u1ee9a ch\u01b0a t\u1eebng h\u1ecdc ti\u1ebfp \u0111\u01b0\u1ee3c con s\u1ed1 th\u1ee9 m\u01b0\u1eddi m\u1ed9t.","Con t\xe0u n\xe0y t\u1eebng ch\u1edf b\u1ecdn tr\u1ebb m\u1ed3 c\xf4i b\u1ecb b\xe1n cho h\u1ea7m m\u1ecf \u1edf h\u1ea3i ngo\u1ea1i. \u0110\u1ec3 ch\xfang kh\u1ecfi k\xeau kh\xf3c, b\u1ecdn ch\u1ee7 bu\xf4n b\u1eaft c\u1ea3 khoang ph\u1ea3i \u0111\u1ebfm s\u1ed1 theo nh\u1ecbp roi; \u0111\u1ee9a n\xe0o d\u1eebng tr\u01b0\u1edbc s\u1ebd b\u1ecb n\xe9m xu\u1ed1ng bi\u1ec3n l\xe0m g\u01b0\u01a1ng. Khi khe n\u1ee9t kh\xf4ng gian nu\u1ed1t c\u1ea3 t\xe0u v\xe0o \u0111\xe2y, ti\u1ebfng \u0111\u1ebfm v\u1eabn c\xf2n m\u1eafc l\u1ea1i trong g\u1ed7 m\u1ee5c. Ta ph\xe1 tan o\xe1n l\u1ef1c nh\u01b0ng kh\xf4ng x\xf3a \u0111\u01b0\u1ee3c con s\u1ed1 \u1ea5y kh\u1ecfi \u0111\u1ea7u m\xecnh, v\xec c\xf3 nh\u1eefng n\u1ed7i \u0111au khi \u0111\u01b0\u1ee3c nghe th\u1ea5y r\u1ed3i s\u1ebd \u1edf l\u1ea1i v\u0129nh vi\u1ec5n nh\u01b0 m\u1ed9t m\xf3n n\u1ee3 ph\u1ea3i nh\u1edb.",null)
B.agR=new A.b3("H\u1ebbm ng\xf3i \xfap treo \u0111\u1ea7y b\xf3ng \xe1o tr\u1ebb con, nh\u01b0ng gi\xf3 th\u1ed5i qua kh\xf4ng l\xe0m ch\xfang lay \u0111\u1ed9ng. C\xf3 l\u1ebd v\xec nh\u1eefng chi\u1ebfc \xe1o \u1ea5y ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c tr\u1ea3 l\u1ea1i cho ch\u1ee7 nh\xe2n c\u1ee7a m\xecnh.","Ng\u01b0\u1eddi th\u1ee3 may \u1edf \u0111\xe2y chuy\xean kh\xe2u l\u1ea1i y ph\u1ee5c cho ph\u1ea1m nh\xe2n b\u1ecb x\u1eed t\u1eed \u0111\u1ec3 \u0111em b\xe1n l\u1ea7n n\u1eefa. B\xe0 nh\u1eadn ra trong s\u1ed1 \u0111\xf3 c\xf3 \xe1o c\u1ee7a con trai m\xecnh, m\u1ed9t \u0111\u1ee9a b\xe9 \u0111\u01b0a th\u01b0 b\u1ecb k\u1ebft t\u1ed9i gi\u1ea5u m\u1ec7nh l\u1ec7nh ph\u1ea3n lo\u1ea1n ch\u1ec9 v\xec l\u1ee1 l\xe0m r\u01a1i con d\u1ea5u c\u1ee7a quan l\u1edbn. B\xe0 kh\xf4ng d\xe1m k\xeau oan, ch\u1ec9 l\u1eb7ng l\u1ebd kh\xe2u t\u1eebng v\u1ebft r\xe1ch tr\xean \xe1o ng\u01b0\u1eddi kh\xe1c nh\u01b0 th\u1ec3 \u0111ang c\u1ed1 kh\xe2u l\u1ea1i ph\u1ea7n \u0111\u1eddi b\u1ecb x\xe9 n\xe1t c\u1ee7a ch\xednh con. Ta ch\xf4n l\u1ea1i c\xe2y kim xu\u1ed1ng m\xe1i ng\xf3i v\xe0 b\u1ea3o b\xe0 r\u1eb1ng t\u1eeb nay \xe1o c\u1ee7a con trai b\xe0 s\u1ebd kh\xf4ng c\xf2n ph\u1ea3i m\u1eb7c tr\xean ng\u01b0\u1eddi ai kh\xe1c n\u1eefa.",null)
B.agX=new A.b3("Ph\u01b0\u1eddng may b\u1eb1ng gi\xf3 treo h\xe0ng ng\xe0n con di\u1ec1u gi\u1ea5y, nh\u01b0ng con n\xe0o c\u0169ng mang h\xecnh khu\xf4n m\u1eb7t ng\u01b0\u1eddi \u0111\xe3 khu\u1ea5t. M\u1ed7i c\u01a1n gi\xf3 n\u1ed5i l\xean l\xe0 c\u1ea3 khu ph\u1ed1 nh\u01b0 \u0111ang kh\xf3c.","\xd4ng l\xe3o l\xe0m di\u1ec1u t\u1eebng h\u1ee9a v\u1edbi con g\xe1i r\u1eb1ng khi m\xf9a h\u1ed9i t\u1edbi s\u1ebd l\xe0m cho n\xf3 m\u1ed9t con di\u1ec1u l\u1edbn nh\u1ea5t th\xe0nh. Nh\u01b0ng trong ng\xe0y h\u1ed9i, th\xe0nh treo \u0111\u1ed5 s\u1eadp m\u1ed9t \u0111o\u1ea1n v\xec quan coi x\xe2y b\u1edbt v\u1eadt li\u1ec7u b\u1ecf t\xfai, con b\xe9 r\u01a1i kh\u1ecfi m\xe9p t\u01b0\u1eddng tr\u01b0\u1edbc m\u1eaft cha. T\u1eeb \u0111\xf3 \xf4ng ch\u1ec9 l\xe0m di\u1ec1u mang g\u01b0\u01a1ng m\u1eb7t nh\u1eefng \u0111\u1ee9a tr\u1ebb ch\u1ebft oan, th\u1ea3 l\xean tr\u1eddi \u0111\u1ec3 c\u1ea3 th\xe0nh ph\u1ea3i ng\u1ea9ng \u0111\u1ea7u nh\xecn. Ta kh\xf4ng b\u1ea3o \xf4ng qu\xean, ch\u1ec9 gi\xfap \xf4ng gi\u1eef l\u1ea1i con di\u1ec1u cu\u1ed1i c\xf9ng cho ri\xeang con g\xe1i m\xecnh, kh\xf4ng bi\u1ebfn n\xf3 th\xe0nh th\xeam m\u1ed9t m\xf3n h\xe0ng c\u1ee7a n\u1ed7i \u0111au n\u1eefa.",null)
B.ahz=new A.b3("L\u1ea7u H\u1ed3i \xc2m kh\xf4ng c\xf3 nh\u1ea1c c\xf4ng, ch\u1ec9 c\xf3 m\u1ed9t gi\u1ecdng n\u1eef c\u1ee9 l\u1eb7p \u0111i l\u1eb7p l\u1ea1i nh\u1eefng b\u1ea3n \xe1n c\u0169 \u0111\u1ebfn kh\u1ea3n \u0111\u1eb7c. M\u1ed7i l\u1eddi tuy\xean \u0111\u1ecdc ra \u0111\u1ec1u nh\u01b0 m\u1ed9t nh\xe1t k\xe9o c\u1eaft v\xe0o c\u1ed5 h\u1ecdng ng\u01b0\u1eddi s\u1ed1ng.",'C\xf4 g\xe1i \u1ea5y t\u1eebng l\xe0 ng\u01b0\u1eddi h\xe1t trong ph\u1ee7 quan, b\u1ecb \xe9p \u0111\u1ecdc \xe1n thay cho quan huy\u1ec7n m\u1ed7i khi h\xe0nh h\xecnh d\xe2n ngh\xe8o \u0111\u1ec3 t\u1ea1o v\u1ebb "nghi\xeam minh". Trong s\u1ed1 nh\u1eefng b\u1ea3n \xe1n c\xf4 t\u1eebng \u0111\u1ecdc c\xf3 t\xean cha m\xecnh, ng\u01b0\u1eddi d\xe1m \u0111\u1ee9ng ra t\u1ed1 c\xe1o kho l\u01b0\u01a1ng b\u1ecb bi\u1ec3n th\u1ee7. Sau khi cha ch\u1ebft, c\xf4 b\u1ecb gi\u1eef l\u1ea1i l\xe0m loa ph\xe1t thanh cho s\u1ef1 b\u1ea5t c\xf4ng cho t\u1edbi l\xfac h\xf3a th\xe0nh o\xe1n linh. Ta kh\xf4ng c\u1ee9u \u0111\u01b0\u1ee3c qu\xe3ng \u0111\u1eddi \u0111\xe3 b\u1ecb l\u1ee3i d\u1ee5ng, nh\u01b0ng ta c\xf3 th\u1ec3 cho c\xf4 m\u1ed9t l\u1ea7n cu\u1ed1i c\u1ea5t ti\u1ebfng h\xe1t b\u1eb1ng ch\xednh gi\u1ecdng m\xecnh, kh\xf4ng c\xf2n ph\u1ea3i \u0111\u1ecdc h\u1ed9 t\u1ed9i l\u1ed7i c\u1ee7a k\u1ebb kh\xe1c.',null)
B.ahf=new A.b3("Vi\u1ec7n \u0110\xe8n Kh\xe2u Tim s\xe1ng tr\u1eafng nh\u01b0 ph\xf2ng ch\u1eefa b\u1ec7nh, nh\u01b0ng m\xf9i m\xe1u c\u0169 trong gi\xf3 cho th\u1ea5y n\u01a1i n\xe0y t\u1eebng d\xf9ng kim ch\u1ec9 v\xe0o vi\u1ec7c kh\xe1c ngo\xe0i c\u1ee9u ng\u01b0\u1eddi.",'Ch\u1ee7 vi\u1ec7n t\u1eebng n\u1ed5i ti\u1ebfng l\xe0 th\u1ea7n y ch\u1eefa \u0111\u01b0\u1ee3c ch\u1ee9ng m\u1ea5t ng\u1ee7 do \xe1m \u1ea3nh chi\u1ebfn tranh. S\u1ef1 th\u1eadt l\xe0 \xf4ng ta m\u1ed5 l\u1ea5y k\xfd \u1ee9c \u0111au bu\u1ed3n t\u1eeb nh\u1eefng b\u1ec7nh nh\xe2n ngh\xe8o r\u1ed3i \u0111em b\xe1n cho t\u1ea7ng l\u1edbp gi\xe0u c\xf3 l\xe0m th\u1ee9 "d\u01b0\u1ee3c li\u1ec7u b\xecnh th\u1ea3n", \u0111\u1ec3 k\u1ebb c\xf3 ti\u1ec1n ng\u1ee7 y\xean c\xf2n ng\u01b0\u1eddi m\u1ea5t k\xfd \u1ee9c th\xec qu\xean lu\xf4n c\u1ea3 l\xfd do m\xecnh ph\u1ea3i s\u1ed1ng ti\u1ebfp. Ng\u01b0\u1eddi h\u1ecdc tr\xf2 nh\u1ecf ph\u1ee5 vi\u1ec7c cho \xf4ng l\xe0 \u0111\u1ee9a b\xe9 m\u1ed3 c\xf4i, m\u1ed7i ng\xe0y ph\u1ea3i gi\u1eb7t kh\u0103n m\xe1u \u0111\u1ec3 \u0111\u1ed5i l\u1ea5y m\u1ed9t b\xe1t ch\xe1o. Ta \u0111\u1ed1t ph\xf2ng gi\u1ea3i ph\u1eabu v\xe0 d\u1eabn \u0111\u1ee9a b\xe9 ra ngo\xe0i, hi v\u1ecdng l\u1ea7n \u0111\u1ea7u ti\xean n\xf3 \u0111\u01b0\u1ee3c l\u1edbn l\xean trong m\u1ed9t th\u1ebf gi\u1edbi kh\xf4ng xem n\u1ed7i \u0111au c\u1ee7a ng\u01b0\u1eddi ngh\xe8o l\xe0 nguy\xean li\u1ec7u.',null)
B.ahK=new A.b3("Tr\u1ea1i g\u1eb7t gi\u1ea5c m\u01a1 d\u1ef1ng \u0111\u1ea7y l\u1ec1u c\u1ecf r\xe1ch, ng\u01b0\u1eddi trong tr\u1ea1i n\u1eb1m ng\u1ee7 su\u1ed1t m\xe0 m\u1eaft v\u1eabn \u01b0\u1edbt. H\u1ecd nh\u01b0 \u0111ang b\u1ecb b\u1eaft c\xe0y x\u1edbi ngay c\u1ea3 trong m\u01a1.","B\u1ecdn cai tr\u1ea1i d\xf9ng \u0111\u1ed9c d\u01b0\u1ee3c khi\u1ebfn d\xe2n l\u01b0u l\u1ea1c ng\u1ee7 m\xea, r\u1ed3i \xe9p h\u1ecd k\u1ec3 l\u1ea1i k\xfd \u1ee9c \u0111\u1eb9p nh\u1ea5t \u0111\u1ec3 bi\u1ebfn th\xe0nh \u1ea3o c\u1ea3nh b\xe1n cho kh\xe1ch qua \u0111\u01b0\u1eddng. C\u1eb7p anh em b\u1ecb gi\u1eef \u1edf \u0111\xe2y \u0111\xe3 b\u1ecb r\xfat c\u1ea1n t\u1edbi m\u1ee9c ng\u01b0\u1eddi anh qu\xean c\u1ea3 g\u01b0\u01a1ng m\u1eb7t em g\xe1i, c\xf2n c\xf4 b\xe9 ch\u1ec9 c\xf2n nh\u1edb m\u1ed9t chuy\u1ec7n duy nh\u1ea5t l\xe0 m\u1ed7i l\u1ea7n \u0111\xf3i \u0111\u1ec1u chia n\u1eeda c\u1ee7 khoai cho anh. Ta ph\xe1 tr\u1eadn, \u0111\xe1nh th\u1ee9c h\u1ecd d\u1eady, nh\u01b0ng kho\u1ea3nh kh\u1eafc ng\u01b0\u1eddi anh h\u1ecfi em t\xean g\xec v\u1eabn khi\u1ebfn ta th\u1ea5y l\u1ea1nh. C\xf3 nh\u1eefng m\u1ea5t m\xe1t kh\xf4ng \u0111\u1ed5 m\xe1u tr\u01b0\u1edbc m\u1eaft, nh\u01b0ng t\xe0n nh\u1eabn h\u01a1n v\xec ch\xfang l\u1ea5y \u0111i ch\xednh kh\u1ea3 n\u0103ng y\xeau th\u01b0\u01a1ng.",null)
B.ah8=new A.b3("Trong l\xe0ng b\u1ebfp kh\xf4ng l\u1eeda, n\u1ed3i ni\xeau v\u1eabn b\xe0y k\xedn m\xe2m nh\u01b0 s\u1eafp c\xf3 ng\u01b0\u1eddi v\u1ec1 \u0103n c\u01a1m. Ch\u1ec9 l\xe0 \u1edf \u0111\xe2y ch\u1eb3ng ai d\xe1m nh\xf3m l\u1eeda th\u1eadt, v\xec l\u1eeda th\u1eadt s\u1ebd bu\u1ed9c h\u1ecd ch\u1ea5p nh\u1eadn b\u1eefa c\u01a1m \u0111\xe3 ngu\u1ed9i qu\xe1 l\xe2u.","Nh\u1eefng ng\u01b0\u1eddi m\u1eb9 \u1edf l\xe0ng n\xe0y m\u1ea5t con trong n\u1ea1n binh d\u1ecbch \u0111\xe3 l\u1eadp th\xe0nh h\u1ed9i n\u1ea5u c\u01a1m ch\u1edd. M\u1ed7i ng\xe0y h\u1ecd b\xe0y \u0111\u1ee7 b\xe1t \u0111\u0169a cho \u0111\xfang s\u1ed1 ng\u01b0\u1eddi \u0111\xe3 ch\u1ebft, t\u1ef1 nh\u1ee7 r\u1eb1ng n\u1ebfu m\xecnh kh\xf4ng d\u1ecdn m\xe2m th\xec bi\u1ebft \u0111\xe2u l\u0169 tr\u1ebb s\u1ebd t\xecm kh\xf4ng th\u1ea5y \u0111\u01b0\u1eddng v\u1ec1 nh\xe0. K\u1ebb gi\u1eef tr\u1eadn l\u1ee3i d\u1ee5ng n\u1ed7i ch\u1edd \u1ea5y \u0111\u1ec3 nu\xf4i o\xe1n l\u1ef1c, bi\u1ebfn c\u1ea3 l\xe0ng th\xe0nh b\u1ebfp l\u1ea1nh k\xe9o d\xe0i m\xe3i kh\xf4ng th\xf4i. Sau tr\u1eadn, ta c\xf9ng h\u1ecd \u0111\u1ed1t n\xe9n h\u01b0\u01a1ng \u0111\u1ea7u ti\xean thay cho b\u1eefa c\u01a1m ch\u1edd v\xe0 n\xf3i r\u1eb1ng th\u01b0\u01a1ng nh\u1edb kh\xf4ng c\xf3 ngh\u0129a l\xe0 ph\u1ea3i t\u1ef1 ph\u1ea1t m\xecnh s\u1ed1ng m\xe3i trong th\u1eddi kh\u1eafc ch\u01b0a d\xe1m ti\u1ec5n bi\u1ec7t.",null)
B.agV=new A.b3("Nh\xe0 k\xe9n im t\u1edbi m\u1ee9c nghe r\xf5 ti\u1ebfng t\u1eb1m c\u1eafn l\xe1. Nh\u01b0ng trong m\u1ed7i chi\u1ebfc k\xe9n treo l\xean kh\xf4ng ph\u1ea3i t\u01a1 l\u1ee5a, m\xe0 l\xe0 th\u01b0 t\u1eeb \u0111\xe3 \xfaa v\xe0ng ch\u01b0a t\u1eebng \u0111\u01b0\u1ee3c g\u1eedi \u0111i.","Ng\u01b0\u1eddi \u0111\xe0n b\xe0 g\xf3a b\u1ee5a \u1edf \u0111\xe2y ch\xf4n th\u01b0 c\u1ee7a ch\u1ed3ng v\xe0o k\xe9n t\u1eb1m v\xec tin r\u1eb1ng \u0111\u1ebfn m\u1ed9t ng\xe0y n\xe0o \u0111\xf3 t\u1eb1m h\xf3a b\u01b0\u1edbm, th\u01b0 s\u1ebd bay t\u1edbi chi\u1ebfn tr\u01b0\u1eddng v\xe0 k\xe9o ch\u1ed3ng n\xe0ng tr\u1edf l\u1ea1i. N\xe0ng \u0111\xe3 vi\u1ebft su\u1ed1t m\u01b0\u1eddi b\u1ea3y n\u0103m, t\u1eeb l\xfac c\xf2n gi\u1eadn, c\xf2n tr\xe1ch, cho \u0111\u1ebfn khi ch\u1ec9 c\xf2n k\u1ec3 nh\u1eefng chuy\u1ec7n nh\u1ecf nh\u01b0 c\xe2y m\u1eadn sau nh\xe0 ra qu\u1ea3 r\u1ed3i r\u1ee5ng xu\u1ed1ng m\u1ed9t m\xecnh. Khi m\u1edf nh\u1eefng chi\u1ebfc k\xe9n cu\u1ed1i c\xf9ng, ta \u0111\u1ecdc \u0111\u01b0\u1ee3c l\u1eddi th\xfa nh\u1eadn mu\u1ed9n m\xe0ng nh\u1ea5t: n\xe0ng bi\u1ebft ch\u1ed3ng \u0111\xe3 ch\u1ebft t\u1eeb l\xe2u, ch\u1ec9 l\xe0 n\u1ebfu ng\u1eebng vi\u1ebft th\xec ph\u1ea3i th\u1eeba nh\u1eadn cu\u1ed9c \u0111\u1eddi m\xecnh \u0111\xe3 th\u1ef1c s\u1ef1 b\u1ecb b\u1ecf l\u1ea1i. Ta gi\xfap n\xe0ng \u0111\u1ed1t th\u01b0, \u0111\u1ec3 tro bay l\xean thay cho c\xe1nh b\u01b0\u1edbm m\xe0 n\xe0ng \u0111\xe3 ch\u1edd c\u1ea3 n\u1eeda \u0111\u1eddi.",null)
B.agM=new A.b3("S\xe2n kh\u1ea5u kh\xf3i n\xe2u v\u1eabn c\xf2n ti\u1ebfng v\u1ed7 tay, nh\u01b0ng m\u1ed7i tr\xe0ng v\u1ed7 l\u1ea1i ch\u1ea5m d\u1ee9t b\u1eb1ng ti\u1ebfng n\u1ee9c n\u1edf. Kh\xf4ng ai \u1edf \u0111\xe2y ph\xe2n bi\u1ec7t n\u1ed5i \u0111\xe2u l\xe0 bu\u1ed5i di\u1ec5n, \u0111\xe2u l\xe0 l\u1ec5 \u0111\u01b0a tang.","\u0110o\xe0n h\xe1t t\u1eebng mua l\u1ea1i tr\u1ebb lang thang, d\u1ea1y ch\xfang m\xfaa h\xe1t r\u1ed3i \xe9p ti\u1ebfp kh\xe1ch cho \u0111\xe1m ph\xfa h\u1ed9. M\u1ed9t \u0111\xe0o n\u01b0\u01a1ng n\u1ed5i ti\u1ebfng \u0111\xe3 nh\u1eadn nu\xf4i \u0111\u1ee9a b\xe9 b\u1ecb b\xe1n r\u1ebb nh\u1ea5t \u0111o\xe0n, nh\u01b0ng trong \u0111\xeam ch\u1ea1y tr\u1ed1n n\xe0ng b\u1ecb qu\u1ea3n g\xe1nh ch\xe9m ch\u1ebft ngay sau c\xe1nh g\xe0 c\xf2n \u0111\u1ee9a nh\u1ecf b\u1ecb b\u1eaft quay l\u1ea1i s\xe2n kh\u1ea5u nh\u01b0 ch\u01b0a t\u1eebng c\xf3 g\xec x\u1ea3y ra. O\xe1n kh\xed khi\u1ebfn c\u1ea3 g\xe1nh h\xe1t m\u1eafc k\u1eb9t trong m\xe0n nhung ch\xe1y d\u1edf. Ta \u0111\xf3ng l\u1ea1i s\xe2n kh\u1ea5u cu\u1ed1i c\xf9ng, \u0111\u1eb7t \u0111\xf4i gi\xe0y m\xfaa c\u1ee7a n\xe0ng b\xean c\u1ea1nh chi\u1ebfc tr\u1ed1ng con c\u1ee7a \u0111\u1ee9a tr\u1ebb, \u0111\u1ec3 c\xe2u chuy\u1ec7n c\u1ee7a h\u1ecd k\u1ebft th\xfac nh\u01b0 ng\u01b0\u1eddi v\u1edbi ng\u01b0\u1eddi ch\u1ee9 kh\xf4ng ph\u1ea3i nh\u01b0 m\xf3n gi\u1ea3i tr\xed cho kh\xe1ch qua \u0111\u01b0\u1eddng.",null)
B.agO=new A.b3("C\u1ed9t bu\u1ed3m g\xe3y sao c\u1eafm gi\u1eefa c\xe1t, d\u01b0\u1edbi ch\xe2n l\xe0 v\xf4 s\u1ed1 m\u1ea3nh k\xednh thi\xean v\u0103n v\u1ee1. \u1ede \u0111\xe2y ai c\u0169ng ng\u1ea9ng nh\xecn b\u1ea7u tr\u1eddi nh\u01b0 th\u1ec3 tr\xean \u0111\xf3 c\xf2n m\xf3n n\u1ee3 ch\u01b0a \u0111\u01b0\u1ee3c \u0111\xf2i l\u1ea1i.","Ng\u01b0\u1eddi coi tr\u1ea1m sao t\u1eebng l\xe0 th\u1ee7y th\u1ee7 tr\u1ebb, \u0111\u01b0a c\u1ea3 gia \u0111\xecnh l\xean thuy\u1ec1n v\u01b0\u1ee3t bi\u1ec3n t\xecm \u0111\u01b0\u1eddng s\u1ed1ng. \u0110\xeam b\xe3o t\u1edbi, \xf4ng ph\u1ea3i ch\u1ecdn c\u1eaft d\xe2y khoang sau \u0111\u1ec3 c\u1ee9u \u0111\u1ea7u m\u0169i t\xe0u, \u0111\u1ed3ng ngh\u0129a v\u1edbi vi\u1ec7c b\u1ecf l\u1ea1i v\u1ee3 con ch\xecm xu\u1ed1ng v\u1ef1c t\u1ed1i. \xd4ng s\u1ed1ng s\xf3t nh\u01b0ng ng\xe0y n\xe0o c\u0169ng nh\xecn tr\u1eddi \u0111\u1ec3 mong m\u1ed9t v\xec sao r\u01a1i xu\u1ed1ng tr\u1ea3 l\u1ea1i l\u1ef1a ch\u1ecdn kh\xe1c cho m\xecnh. Ta kh\xf4ng th\u1ec3 \u0111\u1ed5i l\u1ea1i \u0111\xeam \u1ea5y, ch\u1ec9 c\xf3 th\u1ec3 d\u1ef1ng l\u1ea1i c\u1ed9t bu\u1ed3m cho th\u1eb3ng v\xe0 n\xf3i r\u1eb1ng \u0111\xf4i khi m\u1ed9t ng\u01b0\u1eddi s\u1ed1ng s\xf3t kh\xf4ng ph\u1ea3i v\xec c\xf3 t\u1ed9i l\u1edbn h\u01a1n, m\xe0 v\xec ph\u1ea3i \u1edf l\u1ea1i \u0111\u1ec3 l\xe0m ch\u1ee9ng cho t\u1ea5t c\u1ea3 nh\u1eefng g\xec \u0111\xe3 m\u1ea5t.",null)
B.ahj=new A.b3("Tr\u1ea1m \u0111\u01b0a linh thuy\u1ec1n x\u1ebfp k\xedn nh\u1eefng con thuy\u1ec1n gi\u1ea5y b\u1eb1ng x\u01b0\u01a1ng c\xe1. Con n\xe0o c\u0169ng mang theo m\u1ed9t \u0111\u1ed3ng ti\u1ec1n, nh\u01b0 th\u1ec3 ng\u01b0\u1eddi l\xe0m ra ch\xfang s\u1ee3 ng\u01b0\u1eddi ch\u1ebft c\xf2n b\u1ecb thi\u1ebfu ph\xed qua s\xf4ng.","B\xe0 l\xe3o canh tr\u1ea1m t\u1eebng c\xf3 m\u1ed9t \u0111o\xe0n con bu\xf4n mu\u1ed1i, ch\xedn ng\u01b0\u1eddi \u0111i bi\u1ec3n th\xec ch\xedn ng\u01b0\u1eddi kh\xf4ng tr\u1edf l\u1ea1i sau m\u1ed9t m\xf9a c\u01b0\u1edbp n\u01b0\u1edbc. V\xec kh\xf4ng t\xecm th\u1ea5y x\xe1c, b\xe0 c\u1ee9 \u0111\xf3ng t\u1eebng chi\u1ebfc linh thuy\u1ec1n v\xe0 b\u1ecf l\xean \u0111\xf3 \u0111\u1ed3ng ti\u1ec1n cu\u1ed1i c\xf9ng c\u1ee7a m\u1ed7i \u0111\u1ee9a con, s\u1ee3 xu\u1ed1ng \xe2m ph\u1ee7 ch\xfang kh\xf4ng \u0111\u1ee7 l\u1ed9 ph\xed m\xe0 b\u1ecb xua \u0111u\u1ed5i. K\u1ebb \u0103n b\xe1m tr\xean n\u1ed7i \u0111au \u1ea5y gi\u1ea3 l\xe0m th\u1ea7y c\xfang, thu l\u1ec5 v\u1eadt c\u1ee7a ng\u01b0\u1eddi m\u1ea5t th\xe2n nh\xe2n r\u1ed3i m\u1eb7c h\u1ecd ti\u1ebfp t\u1ee5c s\u1ed1ng c\xf9ng m\u1eb7c c\u1ea3m. Ta h\u1ea1 h\u1eafn v\xe0 c\xf9ng b\xe0 th\u1ea3 h\u1ebft linh thuy\u1ec1n \u0111i, \u0111\u1ec3 t\u1eeb nay nh\u1eefng chuy\u1ebfn ti\u1ec5n \u0111\u01b0a kh\xf4ng c\xf2n b\u1ecb ai l\u1ee3i d\u1ee5ng n\u1eefa.",null)
B.ahE=new A.b3("Ch\u1ee3 b\u1ee5i Tr\u0103ng T\xe0n b\xe1n to\xe0n nh\u1eefng m\xf3n h\xe0ng v\xf4 h\xecnh. Ng\u01b0\u1eddi mua \u0111\u1ee9ng im nh\u1eafm m\u1eaft r\u1ea5t l\xe2u, r\u1ed3i khi m\u1edf m\u1eaft ra l\u1ea1i qu\xean m\u1ea5t th\u1ee9 qu\xfd nh\u1ea5t c\u1ee7a m\xecnh l\xe0 g\xec.",'\u1ede khu ch\u1ee3 n\xe0y, k\xfd \u1ee9c \u0111\u01b0\u1ee3c \u0111\u1ed5i ngang v\u1edbi thu\u1ed1c men. M\u1ed9t ng\u01b0\u1eddi cha b\xe1n \u0111i ng\xe0y sinh c\u1ee7a con \u0111\u1ec3 l\u1ea5y ti\u1ec1n c\u1ee9u v\u1ee3; m\u1ed9t thi\u1ebfu n\u1eef b\xe1n g\u01b0\u01a1ng m\u1eb7t ng\u01b0\u1eddi y\xeau \u0111\u1ec3 chu\u1ed9c em trai kh\u1ecfi \u0111\xe1m n\xf4 bu\xf4n; m\u1ed9t b\xe0 c\u1ee5 b\xe1n ti\u1ebfng g\u1ecdi "m\u1eb9 \u01a1i" cu\u1ed1i c\xf9ng c\xf2n nh\u1edb \u0111\u01b0\u1ee3c ch\u1ec9 \u0111\u1ec3 mua th\xeam v\xe0i thang thu\u1ed1c gi\u1ea3m \u0111au. Ch\u1ee7 ch\u1ee3 ch\u1eb3ng c\u1ea7n c\u01b0\u1edbp b\xf3c g\xec, h\u1eafn ch\u1ec9 \u0111\u1ee3i ng\u01b0\u1eddi ta tuy\u1ec7t v\u1ecdng t\u1edbi m\u1ee9c t\u1ef1 tay c\u1eaft b\u1ecf ph\u1ea7n ng\u01b0\u1eddi nh\u1ea5t c\u1ee7a m\xecnh. Ta ph\xe1 khu ch\u1ee3 \u1ea5y v\xe0 nh\xecn \u0111\xe1m ng\u01b0\u1eddi v\u1eeba tho\xe1t ra b\xe0ng ho\xe0ng \xf4m l\u1ea5y n\u1ed7i \u0111au \u0111\xe3 quay v\u1ec1, b\u1edfi h\xf3a ra \u0111\u01b0\u1ee3c nh\u1edb c\u0169ng l\xe0 m\u1ed9t \u0111\u1eb7c quy\u1ec1n \u0111au \u0111\u1edbn m\xe0 con ng\u01b0\u1eddi ph\u1ea3i gi\u1eef l\u1ea5y.',null)
B.ahD=new A.b3("C\u1ea7u treo qu\xean m\u1eb7t ph\u1ee7 \u0111\u1ea7y s\u01b0\u01a1ng, ai b\u01b0\u1edbc qua c\u0169ng nh\xecn ng\u01b0\u1eddi \u0111i c\xf9ng nh\u01b0 ng\u01b0\u1eddi l\u1ea1. C\xf3 l\u1ebd n\u01a1i n\xe0y t\u1eebng ch\u1ee9ng ki\u1ebfn qu\xe1 nhi\u1ec1u k\u1ebb th\u01b0\u01a1ng nhau m\xe0 v\u1eabn kh\xf4ng th\u1ec3 nh\u1eadn ra nhau l\u1ea7n cu\u1ed1i.","Hai v\u1ee3 ch\u1ed3ng ch\u1ea1y n\u1ea1n t\u1eebng h\u1eb9n n\u1ebfu l\u1ea1c nhau s\u1ebd g\u1eb7p l\u1ea1i tr\xean chi\u1ebfc c\u1ea7u n\xe0y. Nh\u01b0ng \u0111\u1ec3 tho\xe1t kh\u1ecfi b\u1ecdn s\u0103n ng\u01b0\u1eddi, h\u1ecd b\u1ecb \xe9p u\u1ed1ng th\u1ee9 thu\u1ed1c x\xf3a d\u1ea7n k\xfd \u1ee9c nh\u1eadn di\u1ec7n \u0111\u1ec3 kh\u1ecfi khai t\xean nhau khi b\u1ecb tra kh\u1ea3o. H\u1ecd s\u1ed1ng s\xf3t, c\xf9ng tr\u1edf l\u1ea1i c\xe2y c\u1ea7u \u0111\xfang ng\xe0y h\u1eb9n, v\u1eady m\xe0 ch\u1ec9 \u0111\u1ee9ng c\xe1ch nhau v\xe0i b\u01b0\u1edbc r\u1ed3i l\u01b0\u1edbt qua nh\u01b0 hai ng\u01b0\u1eddi qua \u0111\u01b0\u1eddng. O\xe1n kh\xed c\u1ee7a l\u1eddi h\u1eb9n th\u1ea5t l\u1ea1c gi\u1eef c\u1ea3 chi\u1ebfc c\u1ea7u l\u1ea1i gi\u1eefa Tinh M\u1ed9. Sau tr\u1eadn, ta \u0111\u1eb7t \u0111\xf4i gu\u1ed1c c\u1ee7a ng\u01b0\u1eddi v\u1ee3 c\u1ea1nh c\xe2y s\xe1o c\u1ee7a ng\u01b0\u1eddi ch\u1ed3ng, mong \xedt nh\u1ea5t \u1edf m\u1ed9t n\u01a1i n\xe0o \u0111\xf3 ngo\xe0i th\u1ebf gi\u1edbi n\xe0y h\u1ecd s\u1ebd nh\u1eadn ra nhau k\u1ecbp l\xfac.",null)
B.ah4=new A.b3("H\u1ed3 g\u01b0\u01a1ng kh\xf4ng ph\u1ea3n chi\u1ebfu m\u1eb7t ng\u01b0\u1eddi \u0111ang s\u1ed1ng, ch\u1ec9 hi\u1ec7n ra ng\u01b0\u1eddi m\xe0 m\xecnh th\u01b0\u01a1ng nh\u1ea5t l\xfac h\u1ecd c\xf2n ch\u01b0a ch\u1ebft. C\xe0ng nh\xecn l\xe2u c\xe0ng kh\xf3 ph\xe2n bi\u1ec7t \u0111\xe2u l\xe0 th\u01b0\u01a1ng nh\u1edb, \u0111\xe2u l\xe0 c\xe1m d\u1ed7.",'Ng\u01b0\u1eddi \u0111\xe0n b\xe0 canh h\u1ed3 t\u1edbi \u0111\xe2y m\u1ed7i ng\xe0y \u0111\u1ec3 nh\xecn \u0111\u1ee9a con g\xe1i m\u1ea5t v\xec b\u1ec7nh s\u1ed1t n\u0103m m\u01b0\u1eddi hai tu\u1ed5i. \u0110\u1ec3 \u0111\u01b0\u1ee3c th\u1ea5y con th\xeam l\xe2u, b\xe0 ch\u1ea5p nh\u1eadn l\xe0m l\u1ec5 hi\u1ebfn k\xfd \u1ee9c cho h\u1ed3, \u0111\u1ed5i d\u1ea7n c\u1ea3 tu\u1ed5i tr\u1ebb, gi\u1ecdng n\xf3i v\xe0 t\xean m\xecnh ch\u1ec9 l\u1ea5y th\xeam v\xe0i kh\u1eafc \u1ea3o \u1ea3nh. \u0110\u1ebfn l\xfac ta g\u1eb7p, b\xe0 ch\u1ec9 c\xf2n bi\u1ebft g\u1ecdi "con \u01a1i" m\xe0 kh\xf4ng nh\u1edb m\xecnh l\xe0 ai. Ta ph\xe1 m\u1eb7t h\u1ed3, gi\u1eef l\u1ea1i cho b\xe0 m\u1ea3nh g\u01b0\u01a1ng nh\u1ecf kh\u1eafc t\xean con g\xe1i, \u0111\u1ec3 k\xfd \u1ee9c cu\u1ed1i c\xf9ng c\xf2n s\xf3t l\u1ea1i kh\xf4ng ti\u1ebfp t\u1ee5c b\u1ecb m\u1ed9t \u1ea3o c\u1ea3nh v\xf4 \u0111\xe1y g\u1eb7m nh\u1ea5m.',null)
B.ahq=new A.b3("V\u01b0\u1eddn thu\u1ed1c n\u1edf to\xe0n hoa tr\u1eafng m\u1ecdc tr\xean \u0111\u1ea5t l\u1ea1nh nh\u01b0 m\u1ed3 ch\xf4n. H\u01b0\u01a1ng thu\u1ed1c th\u01a1m \u0111\u1ebfn m\u1ee9c khi\u1ebfn ng\u01b0\u1eddi ta qu\xean m\u1ea5t mu\u1ed1n h\u1ecfi c\xe2y n\xe0y \u0111\xe3 h\xfat d\u01b0\u1ee1ng ch\u1ea5t t\u1eeb \u0111\xe2u m\xe0 s\u1ed1ng.","D\u01b0\u1ee3c s\u01b0 c\u1ee7a v\u01b0\u1eddn t\u1eebng c\u1ee9u \u0111\u01b0\u1ee3c v\xf4 s\u1ed1 ng\u01b0\u1eddi, nh\u01b0ng v\xec m\u1ea5t v\u1ee3 con trong d\u1ecbch b\u1ec7nh \xf4ng \u0111i\xean cu\u1ed3ng th\u1eed m\u1ecdi c\xe1ch g\u1ecdi h\u1ed3n tr\u1edf l\u1ea1i. \xd4ng tr\u1ed3ng thu\u1ed1c tr\xean h\xe0i c\u1ed1t b\u1ec7nh nh\xe2n v\xf4 th\u1eeba nh\u1eadn, tin r\u1eb1ng d\u01b0\u1ee3c l\u1ef1c m\u1ea1nh l\xean s\u1ebd \u0111\u1ed5i \u0111\u01b0\u1ee3c m\u1ed9t ph\xe9p m\xe0u, v\xe0 d\u1ea7n d\u1ea7n kh\xf4ng c\xf2n ph\xe2n bi\u1ec7t \u0111\u01b0\u1ee3c c\u1ee9u ng\u01b0\u1eddi v\u1edbi l\u1ee3i d\u1ee5ng ng\u01b0\u1eddi ch\u1ebft n\u1eefa. K\u1ebb \u0111\xe1ng th\u01b0\u01a1ng khi l\u1ea1c \u0111\u01b0\u1eddng v\u1eabn c\xf3 th\u1ec3 tr\u1edf th\xe0nh ngu\u1ed3n g\u1ed1c c\u1ee7a \u0111au th\u01b0\u01a1ng cho ng\u01b0\u1eddi kh\xe1c. Ta ch\xf4n l\u1ea1i x\u01b0\u01a1ng c\u1ed1t nh\u1eefng ng\u01b0\u1eddi b\u1ecb \xf4ng d\xf9ng l\xe0m \u0111\u1ea5t tr\u1ed3ng v\xe0 \u0111\u1ec3 l\u1ea1i m\u1ed9t t\u1ea5m bia ghi c\xf4ng l\u1eabn t\u1ed9i, v\xec m\u1ed9t \u0111\u1eddi ng\u01b0\u1eddi kh\xf4ng ph\u1ea3i l\xfac n\xe0o c\u0169ng ch\u1ec9 c\xf3 m\u1ed9t m\xe0u \u0111\u1ec3 ph\xe1n x\xe9t.",null)
B.ah_=new A.b3("H\xe0nh vi\u1ec7n t\u1ea1p d\u1ecbch v\u1eabn c\xf3 ng\u01b0\u1eddi qu\xe9t s\xe2n, gi\u1eb7t \xe1o, b\u01b0ng \u0111\xe8n nh\u01b0 ch\u1ee7 nh\xe2n n\u01a1i n\xe0y c\xf2n s\u1ed1ng. Nh\xecn h\u1ecd, ta ch\u1ec9 th\u1ea5y m\u1ed9t th\u1ee9 trung th\xe0nh \u0111au t\u1edbi m\u1ee9c \u0111\xe3 h\xf3a th\xe0nh xi\u1ec1ng x\xedch.",'Nh\u1eefng gia nh\xe2n \u1edf \u0111\xe2y \u0111\xe3 theo v\u1ecb ch\u1ee7 nh\xe2n v\xf4 danh c\u1ee7a ph\u1ee7 \u0111\u1ec7 n\xe0y su\u1ed1t nhi\u1ec1u n\u0103m \u0111\xe0o vong. Khi ch\u1ee7 nh\xe2n ch\u1ebft, h\u1ecd kh\xf4ng ch\u1ecbu r\u1eddi \u0111i v\xec ngh\u0129 ch\u1ec9 c\u1ea7n ph\u1ee7 \u0111\u1ec7 c\xf2n v\u1eadn h\xe0nh th\xec ng\u01b0\u1eddi \u0111\xe3 khu\u1ea5t s\u1ebd m\u1ed9t ng\xe0y tr\u1edf v\u1ec1. C\xf3 ng\u01b0\u1eddi qu\xe9t s\xe2n ba tr\u0103m n\u0103m, c\xf3 ng\u01b0\u1eddi ng\xe0y n\xe0o c\u0169ng n\u1ea5u m\u1ed9t n\u1ed3i ch\xe1o r\u1ed3i \u0111\u1ec3 ngu\u1ed9i, c\xf3 ng\u01b0\u1eddi gi\u1eef nguy\xean l\u1eddi d\u1eb7n cu\u1ed1i c\xf9ng \u0111\u1ebfn m\u1ee9c qu\xean m\u1ea5t \u0111\u1eddi m\xecnh t\u1eebng c\xf3 t\xean kh\xe1c ngo\xe0i "n\xf4 b\u1ed9c". Ta gi\u1ea3i tr\u1eadn cho h\u1ecd kh\xf4ng ph\u1ea3i b\u1eb1ng c\xe1ch ch\xea tr\xe1ch l\xf2ng trung, m\xe0 b\u1eb1ng c\xe1ch n\xf3i m\u1ed9t c\xe2u \u0111\u01a1n gi\u1ea3n: ng\u01b0\u1eddi ch\u1ebft r\u1ed3i, c\xe1c ng\u01b0\u01a1i c\u0169ng n\xean \u0111\u01b0\u1ee3c ph\xe9p s\u1ed1ng ph\u1ea7n \u0111\u1eddi c\xf2n l\u1ea1i c\u1ee7a ch\xednh m\xecnh.',null)
B.ahF=new A.b3("C\u1ea7u r\xeau d\u1eabn ph\u1ee7 b\u1eafc qua m\u1ed9t khe t\u1ed1i kh\xf4ng \u0111\xe1y, \u0111\u1ea7u c\u1ea7u c\u1eafm v\xf4 s\u1ed1 g\u1eady d\u1eabn \u0111\u01b0\u1eddng \u0111\xe3 m\u1ee5c. C\xf3 m\u1ed9t ng\u01b0\u1eddi ch\xe8o ch\u1ed1ng m\xe3i \u1edf \u0111\xe2y m\xe0 ch\u01b0a t\u1eebng b\u01b0\u1edbc sang ph\xeda b\xean kia.",'Ng\u01b0\u1eddi d\u1eabn l\u1ed1i t\u1eebng l\xe0 k\u1ebb chuy\xean d\u1eabn d\xe2n t\u1ecb n\u1ea1n qua v\xf9ng lo\u1ea1n \u0111\u1ed5i l\u1ea5y ch\xfat ti\u1ec1n c\u01a1m. M\u1ed9t l\u1ea7n v\xec s\u1ee3 li\xean l\u1ee5y, anh b\u1ecf l\u1ea1i c\u1ea3 \u0111o\xe0n gi\u1eefa b\xe3i s\u0103n c\u1ee7a qu\xe2n l\xednh r\u1ed3i tr\u1ed1n tr\u01b0\u1edbc, khi\u1ebfn m\u01b0\u1eddi b\u1ea3y ng\u01b0\u1eddi ch\u1ebft trong \u0111\xeam trong \u0111\xf3 c\xf3 c\xf4 g\xe1i \u0111ang mang thai \u0111\xe3 g\u1ecdi anh l\xe0 "ca ca" su\u1ed1t qu\xe3ng \u0111\u01b0\u1eddng \u0111i. T\u1eeb \u0111\xf3, \u1edf Th\u01b0\u1ee3ng Uy\xean anh b\u1ecb gi\u1eef l\xe0m ng\u01b0\u1eddi d\u1eabn \u0111\u01b0\u1eddng cho linh h\u1ed3n qua chi\u1ebfc c\u1ea7u n\xe0y, nh\u01b0ng kh\xf4ng bao gi\u1edd \u0111\u01b0\u1ee3c t\u1ef1 m\xecnh b\u01b0\u1edbc sang. Ta kh\xf4ng tha th\u1ee9 thay nh\u1eefng ng\u01b0\u1eddi ch\u1ebft, nh\u01b0ng ta cho anh quy\u1ec1n \u0111\u1eb7t c\xe2y s\xe0o xu\u1ed1ng v\xe0 qu\u1ef3 tr\u01b0\u1edbc c\xe2y c\u1ea7u, l\u1ea7n \u0111\u1ea7u ti\xean g\u1ecdi \u0111\xfang t\xean n\u1ed7i h\xe8n nh\xe1t \u0111\xe3 ph\xe1 h\u1ee7y c\u1ea3 m\u1ed9t \u0111o\xe0n ng\u01b0\u1eddi.',null)
